import hmac
import hashlib
import struct
import time
import base64
import io
import qrcode
from urllib.parse import quote


class TOTPAuthenticator:
    def __init__(self, issuer_name="MyApp", time_step=30, digits=6):
        self.issuer_name = issuer_name
        self.time_step = time_step
        self.digits = digits

    def generate_secret(self, length=32):
        import secrets
        alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567"
        secret = ''.join(secrets.choice(alphabet) for _ in range(length))
        return secret

    def _base32_decode(self, secret):
        missing_padding = len(secret) % 8
        if missing_padding:
            secret += '=' * (8 - missing_padding)
        return base64.b32decode(secret, casefold=True)

    def _generate_hotp(self, secret, counter):
        key = self._base32_decode(secret)
        counter_bytes = struct.pack(">Q", counter)
        hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
        offset = hmac_hash[-1] & 0x0F
        truncated_hash = struct.unpack(">I", hmac_hash[offset:offset + 4])[0]
        truncated_hash &= 0x7FFFFFFF
        otp = truncated_hash % (10 ** self.digits)
        return str(otp).zfill(self.digits)

    def get_totp(self, secret, timestamp=None):
        if timestamp is None:
            timestamp = time.time()
        counter = int(timestamp // self.time_step)
        return self._generate_hotp(secret, counter)

    def verify_totp(self, secret, token, timestamp=None, window=1):
        if timestamp is None:
            timestamp = time.time()
        
        current_counter = int(timestamp // self.time_step)
        
        for offset in range(-window, window + 1):
            counter = current_counter + offset
            expected_token = self._generate_hotp(secret, counter)
            if hmac.compare_digest(expected_token, str(token)):
                return True
        return False

    def get_provisioning_uri(self, secret, account_name, issuer_name=None):
        if issuer_name is None:
            issuer_name = self.issuer_name
        
        label = f"{issuer_name}:{account_name}"
        params = {
            'secret': secret,
            'issuer': issuer_name,
            'algorithm': 'SHA1',
            'digits': self.digits,
            'period': self.time_step
        }
        
        query_string = '&'.join([f"{k}={quote(str(v))}" for k, v in params.items()])
        uri = f"otpauth://totp/{quote(label)}?{query_string}"
        return uri

    def generate_qr_code(self, secret, account_name, issuer_name=None):
        uri = self.get_provisioning_uri(secret, account_name, issuer_name)
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        img = qr.make_image(fill_color="black", back_color="white")
        return img

    def generate_qr_code_base64(self, secret, account_name, issuer_name=None):
        img = self.generate_qr_code(secret, account_name, issuer_name)
        buffered = io.BytesIO()
        img.save(buffered, format="PNG")
        img_str = base64.b64encode(buffered.getvalue()).decode()
        return img_str


class UserTOTPManager:
    def __init__(self, issuer_name="MyApp"):
        self.authenticator = TOTPAuthenticator(issuer_name=issuer_name)
        self.users = {}

    def register_user(self, username, email=None):
        if username in self.users:
            raise ValueError(f"User {username} already exists")
        
        secret = self.authenticator.generate_secret()
        account_name = email if email else username
        
        self.users[username] = {
            'secret': secret,
            'email': email,
            'account_name': account_name,
            'enabled': True,
            'backup_codes': self._generate_backup_codes()
        }
        
        return {
            'username': username,
            'secret': secret,
            'qr_uri': self.authenticator.get_provisioning_uri(secret, account_name),
            'backup_codes': self.users[username]['backup_codes']
        }

    def _generate_backup_codes(self, count=10):
        import secrets
        codes = []
        for _ in range(count):
            code = ''.join([str(secrets.randbelow(10)) for _ in range(8)])
            formatted_code = f"{code[:4]}-{code[4:]}"
            codes.append(formatted_code)
        return codes

    def get_qr_code(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username]
        return self.authenticator.generate_qr_code(
            user_data['secret'],
            user_data['account_name']
        )

    def get_qr_code_base64(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username]
        return self.authenticator.generate_qr_code_base64(
            user_data['secret'],
            user_data['account_name']
        )

    def verify_user_totp(self, username, token, use_backup=False):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username]
        
        if not user_data['enabled']:
            return False
        
        if use_backup:
            formatted_token = token
            if '-' not in token and len(token) == 8:
                formatted_token = f"{token[:4]}-{token[4:]}"
            
            if formatted_token in user_data['backup_codes']:
                user_data['backup_codes'].remove(formatted_token)
                return True
            return False
        
        return self.authenticator.verify_totp(user_data['secret'], token)

    def disable_totp(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        self.users[username]['enabled'] = False

    def enable_totp(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        self.users[username]['enabled'] = True

    def get_user_info(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username].copy()
        return {
            'username': username,
            'email': user_data['email'],
            'enabled': user_data['enabled'],
            'backup_codes_remaining': len(user_data['backup_codes'])
        }

    def regenerate_backup_codes(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        self.users[username]['backup_codes'] = self._generate_backup_codes()
        return self.users[username]['backup_codes']


